  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires identifying a general scaling exponent (De Giorgi exponent) that applies to a class of dissipative PDEs characterized by dimension n and diffusion order s. The solution must be verified against a specific list of equations to ensure universality.",
  "helpers": [
    {
      "label": "derive_general_scaling_exponent",
      "instructions": "Determine the scaling exponent $\alpha$ (or $\gamma$) for a general dissipative PDE of the form $\partial_t u + (u \cdot \nabla)u + (-\Delta)^s u = 0$ in $n$ dimensions. Use dimensional analysis or scaling symmetry $u_\lambda(x, t) = \lambda^\alpha u(\lambda x, \lambda^{2s} t)$ to find the critical exponent that renders the equation scale-invariant or defines the regularity threshold."
    },
    {
      "label": "verify_exponent_for_specific_pdes",
      "instructions": "For the following PDEs, calculate their specific critical scaling exponent and check if it matches the general formula derived in the previous step: 1) 3D Navier-Stokes (n=3, s=1), 2) 2D Navier-Stokes (n=2, s=1), 3) 1D Burgers (n=1, s=1), 4) Surface Quasi-Geostrophic (SQG) (n=2, s=1/2 or general s), 5) Magnetohydrodynamics (MHD) (n=3, s=1), 6) Fractional Navier-Stokes (n=3, general s)."
    },
    {
      "label": "validate_de_giorgi_context",
      "instructions": "Confirm if the derived exponent corresponds to the 'De Giorgi' type regularity threshold (often related to the critical space $L^p$ or Sobolev space $H^s$ where the nonlinearity and dissipation balance) as used in the context of global regularity for dissipative systems."
    }
  ],
  "synthesis_brief": "Combine the general formula derived by helper_1 with the verification results from helper_2. If the formula consistently predicts the correct critical exponents for all 6 listed PDEs, provide the general formula as the FINAL_ANSWER and use the successful verifications as the JUSTIFICATION."
}
